transform_js:
var groups = {};
rawData.rows.forEach(function(r) {
  if (!groups[r.group]) groups[r.group] = [];
  groups[r.group].push({ name: r.name, value: r.val });
});
var children = Object.keys(groups).map(function(g) {
  return { name: g, children: groups[g] };
});
transformedData = { name: 'root', children: children };

echarts_js:
option = {
  title: { text: 'Market Cap (Packed Bubbles)', left: 'center' },
  tooltip: { formatter: function(p) { return p.name + ': ' + (p.value || ''); } },
  series: [{
    type: 'tree',
    data: [transformedData],
    layout: 'radial',
    symbol: 'circle',
    symbolSize: function(v) { return v ? Math.sqrt(v) * 4 : 10; },
    label: { show: true, fontSize: 10 },
    itemStyle: { borderWidth: 1, borderColor: '#fff' },
    roam: true
  }]
};
